use hex;

use iso_8583_message::IsoMessage;

/*
"0":"0100",
"3":"300000",
"4":"000000000400",
"6":"000000000400",
"7":"0930142058",
"10":"61000000",
"11":"012688",
"12":"092058",
"13":"0930",
"14":"2510",
"15":"0930",
"16":"0929",
"18":"6011",
"22":"901",
"28":"D00000400",
"32":"002202",
"37":"340170100001",
"41":"MTFT3TST",
"42":"MASTER IDF/C   ",
"43":"EATING PLACES, RESTAUR TORONTO       CAN",
"48":"Z",
"49":"124",
"51":"124",
"52":"3a52bfe4207e895d",
"61":"000000000180012490210     ",
"63":"MCS2MK90X"
*/
#[test]
fn end_to_end() {
    let hex_string = "";
    let buffer = hex::decode(hex_string).unwrap();

    let iso_message = IsoMessage::from_buffer(buffer.clone()).unwrap();

    let new_buffer = iso_message.get_message_buffer().unwrap();

    assert_eq!(buffer, new_buffer);
}
